#!/usr/bin/env pwsh
# Create GitHub issues for Spec 009: User Directory
# Repository: microsoft/CommunityManagement-Sample-Spec-Kit

$env:Path += ";$env:LOCALAPPDATA\gh-cli\bin"
$repo = "microsoft/CommunityManagement-Sample-Spec-Kit"

# Define all issues as structured data
$issues = @(
    # Phase 1: Setup
    @{ id="T001"; title="Create directory structure per plan.md"; phase="phase:setup"; priority="priority:P1"; parallel=$false; story=""; body="Create directory structure per plan.md:`n- apps/web/src/lib/directory/`n- apps/web/src/components/directory/`n- apps/web/src/app/api/directory/`n- apps/web/src/app/directory/`n- apps/web/tests/integration/directory/`n- packages/shared-ui/src/DirectoryCard/`n- packages/shared-ui/src/SocialIcons/`n`n**Spec**: specs/009-user-directory/spec.md" }
    @{ id="T002"; title="Create migration 009_user_directory.sql"; phase="phase:setup"; priority="priority:P1"; parallel=$false; story=""; body="Create database migration file apps/web/src/db/migrations/009_user_directory.sql`n- ALTER TABLE user_profiles ADD COLUMN directory_visible BOOLEAN NOT NULL DEFAULT false`n- Expand social_links platform CHECK constraint from 4 to 8 values`n- Create 5 partial indexes per data-model.md`n`n**Spec**: specs/009-user-directory/data-model.md" }
    @{ id="T003"; title="Create shared directory types"; phase="phase:setup"; priority="priority:P1"; parallel=$true; story=""; body="Create shared directory types in packages/shared/src/types/directory.ts`n- DirectoryEntry, DirectoryQueryParams, DirectoryResponse`n- DirectorySortMode, RelationshipFilter, RelationshipStatus`n- VisibleSocialLink, ProfileCompleteness`n`n**Contract**: specs/009-user-directory/contracts/directory-api.ts" }
    @{ id="T004"; title="Expand SocialPlatform type to 8 values"; phase="phase:setup"; priority="priority:P1"; parallel=$true; story=""; body="Expand SocialPlatform type in packages/shared/src/types/community.ts`nAdd: tiktok, twitter_x, linkedin, threads to existing 4-value union type`n`n**FR**: FR-023`n**Research**: R-1" }
    @{ id="T005"; title="Create Zod validation schemas for directory"; phase="phase:setup"; priority="priority:P1"; parallel=$true; story=""; body="Create Zod validation schemas in apps/web/src/lib/directory/schemas.ts`n- DirectoryQueryParamsSchema (cursor, pageSize 1-100 default 20, sort, role, city, country, continent, teachersOnly, relationship, search)`n- CursorSchema for decode validation" }
    @{ id="T006"; title="Create PGlite test seed helpers"; phase="phase:setup"; priority="priority:P1"; parallel=$true; story=""; body="Create PGlite test seed helpers in apps/web/tests/integration/directory/helpers.ts`n- seedDirectoryUsers() creating 10+ users with varied directory_visible states, roles, cities, teacher profiles, social links at various visibility levels, follow/block pairs, and mutual follows (friends)" }

    # Phase 2: Foundational
    @{ id="T007"; title="Implement cursor encode/decode utilities"; phase="phase:foundational"; priority="priority:P1"; parallel=$false; story=""; body="Implement cursor encode/decode utilities in apps/web/src/lib/directory/cursor.ts`n- encodeCursor(sortValue, id) -> base64 opaque string`n- decodeCursor(cursor) -> validated {sortValue, id} with Zod`n`n**Research**: R-2" }
    @{ id="T008"; title="Implement base directory SQL query builder"; phase="phase:foundational"; priority="priority:P1"; parallel=$false; story=""; body="Implement base directory SQL query builder in apps/web/src/lib/directory/service.ts`n- Core SELECT joining user_profiles + geography + teacher_profiles + social_links`n- Block exclusion via NOT EXISTS (symmetric)`n- Social link visibility FILTER clause`n- GROUP BY, LIMIT pageSize+1, self-exclusion`n`n**Research**: R-4, R-6" }
    @{ id="T009"; title="Update Zod SocialPlatform schema to 8 values"; phase="phase:foundational"; priority="priority:P1"; parallel=$true; story=""; body="Update existing Zod SocialPlatform schema in apps/web/src/lib/validation/community-schemas.ts (or equivalent) to match expanded 8-value enum. Ensure Spec 002 validation layer accepts new platforms." }

    # Phase 3: US1 Browse (P1 MVP)
