    @{ id="T011"; title="Test: cursor pagination + hasNextPage"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US1"; body="Integration test: cursor pagination + hasNextPage`nFile: apps/web/tests/integration/directory/directory-listing.test.ts`n- Seed 25 visible users, fetch page 1 (20), assert hasNextPage=true + nextCursor`n- Fetch page 2, assert 5 results + hasNextPage=false`n`n**FR**: FR-003" }
    @{ id="T012"; title="Implement getDirectoryPage() service"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US1"; body="Implement getDirectoryPage() in apps/web/src/lib/directory/service.ts`n- Accepts DirectoryQueryParams + viewerId`n- Executes base query with directory_visible=true filter`n- Cursor pagination, returns {entries, nextCursor, hasNextPage}`n`n**FR**: FR-001, FR-003, FR-004" }
    @{ id="T013"; title="Implement GET /api/directory route"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US1"; body="Implement GET /api/directory route in apps/web/src/app/api/directory/route.ts`n- requireAuth(), parse + validate query params with DirectoryQueryParamsSchema`n- Call getDirectoryPage(), return DirectoryResponse`n- 401 on unauth, 400 on invalid params" }
