    @{ id="T016"; title="Create directory browse page"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US1"; body="Create directory browse page in apps/web/src/app/directory/page.tsx`n- Server component for initial data fetch`n- Hydrate DirectoryList with first page of results`n`n**FR**: FR-001" }
