    @{ id="T018"; title="Test: role filter returns correct subset"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US2"; body="Integration test: role filter`nFile: apps/web/tests/integration/directory/directory-filters.test.ts`n- Seed users with Base/Flyer/Hybrid roles`n- Filter role=flyer, assert only Flyers returned`n`n**FR**: FR-005" }
    @{ id="T019"; title="Test: location filters (city/country/continent)"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US2"; body="Integration test: location filters`nFile: apps/web/tests/integration/directory/directory-filters.test.ts`n- Seed users across Bristol/London/Paris`n- Filter country=UK, assert only UK users`n`n**FR**: FR-006" }
