    @{ id="T025"; title="Create DirectoryFilters component"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US2"; body="Create DirectoryFilters component in apps/web/src/components/directory/DirectoryFilters.tsx`n- Role dropdown (Base/Flyer/Hybrid/All)`n- Location selector (city/country/continent from geography)`n- Teacher toggle, sort selector, text search input`n- Clear-all button`n`n**FR**: FR-005 through FR-012" }
    @{ id="T026"; title="Integrate DirectoryFilters with page"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US2"; body="Integrate DirectoryFilters with directory page`n- Sync filter state to URL search params`n- Re-fetch API on filter change, reset cursor on filter change`n- Clear-all resets to unfiltered view`n`n**FR**: FR-011, FR-012" }

    # Phase 5: US3 Visibility (P1)
    @{ id="T027"; title="Test: directory_visible default + toggle"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US3"; body="Integration test: default directory_visible=false and toggle behavior`nFile: apps/web/tests/integration/directory/directory-visibility.test.ts`n- Create user, assert not in directory`n- Toggle on via PATCH, assert in directory`n- Toggle off, assert absent`n`n**FR**: FR-013, FR-014" }
    @{ id="T028"; title="Test: GDPR export/deletion for directoryVisible"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US3"; body="Integration test: GDPR export includes directoryVisible + deletion clears it`nFile: apps/web/tests/integration/directory/directory-visibility.test.ts`n`n**FR**: FR-031, FR-032" }
    @{ id="T028a"; title="Test: direct profile URL works when hidden"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US3"; body="Integration test: direct profile URL works even when directory_visible=false`nFile: apps/web/tests/integration/directory/directory-visibility.test.ts`n- Set user's directory_visible=false`n- GET /api/profiles/:userId as another user`n- Assert 200 with profile data`n`n**FR**: FR-015`n**US3-AS4**" }
    @{ id="T028b"; title="Test: 401 for unauthenticated PATCH toggle"; phase="phase:core"; priority="priority:P1"; parallel=$true; story="US3"; body="Integration test: PATCH /api/profiles/me returns 401 for unauthenticated requests and only updates own profile`nFile: apps/web/tests/integration/directory/directory-visibility.test.ts`n- Verify auth enforcement on directoryVisible toggle`n`n**QG-10**: Permission smoke test" }
    @{ id="T029"; title="Extend PATCH /api/profiles/me for visibility"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US3"; body="Extend PATCH /api/profiles/me to accept directoryVisible field`n- Update Zod request schema in existing route`n- Add directory_visible column to UPDATE SQL`n`n**FR**: FR-014" }
    @{ id="T030"; title="Create DirectoryVisibilityToggle component"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US3"; body="Create DirectoryVisibilityToggle component`nFile: apps/web/src/components/directory/DirectoryVisibilityToggle.tsx`n- Labeled toggle switch with i18n-ready label`n- Calls PATCH /api/profiles/me`n`n**FR**: FR-014" }
    @{ id="T031"; title="Add visibility toggle to profile settings"; phase="phase:core"; priority="priority:P1"; parallel=$false; story="US3"; body="Add DirectoryVisibilityToggle to profile settings page`nFile: apps/web/src/app/settings/profile/page.tsx`n- Place below existing profile fields`n- Load current state from profile data`n`n**FR**: FR-014" }
