    @{ id="T035"; title="Add relationship status derivation to service"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US4"; body="Add relationship status derivation to directory service response mapping`nFile: apps/web/src/lib/directory/service.ts`n- Map viewer_follows + follows_viewer SQL booleans to RelationshipStatus enum`n- (friend/following/follows_me/none) per DirectoryEntry contract`n`n**FR**: FR-019" }
    @{ id="T036"; title="Add relationship status display to card"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US4"; body="Add relationship status display to DirectoryCard`nFile: packages/shared-ui/src/DirectoryCard/DirectoryCard.tsx`n- Badge/label showing Friend/Following/Follows you/None`n- Style per status`n`n**FR**: FR-019" }
    @{ id="T037"; title="Add follow/unfollow action to DirectoryCard"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US4"; body="Add follow/unfollow action button to DirectoryCard`n- Calls existing POST /api/follows and DELETE /api/follows/:userId`n- Optimistic status toggle without full page reload`n`n**FR**: FR-020, FR-022" }
