    @{ id="T040"; title="Create SocialIcons component (5-file)"; phase="phase:core"; priority="priority:P2"; parallel=$true; story="US5"; body="Create SocialIcons component in packages/shared-ui/src/SocialIcons/`n- 5-file pattern: SocialIcons.tsx, SocialIcons.test.tsx, SocialIcons.stories.tsx, index.web.tsx, index.native.tsx`n- Accepts VisibleSocialLink[], renders platform brand icon per platform`n- Each icon is anchor with target='_blank' rel='noopener noreferrer'`n`n**FR**: FR-023, FR-024, FR-025" }
    @{ id="T041"; title="Create platform icon asset map"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US5"; body="Create platform icon asset map in packages/shared-ui/src/SocialIcons/icons.ts`n- Map SocialPlatform -> SVG icon component for all 8 platforms`n- facebook, instagram, youtube, website, tiktok, twitter_x, linkedin, threads`n`n**FR**: FR-024" }
    @{ id="T042"; title="Integrate SocialIcons into DirectoryCard"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US5"; body="Integrate SocialIcons into DirectoryCard`n- Render below city/role area`n- Hide entire social section when visibleSocialLinks is empty`n`n**FR**: FR-025" }

