    @{ id="T044"; title="Add relationship filter to query builder"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US6"; body="Add relationship filter clauses to directory query builder`nFile: apps/web/src/lib/directory/service.ts`n- friends: mutual follow EXISTS`n- following: viewer follows EXISTS`n- followers: followee=viewer EXISTS`n- blocked: blocker_id=viewer EXISTS (inverts normal block exclusion)`n`n**FR**: FR-007`n**Research**: R-7" }
    @{ id="T045"; title="Add relationship filter to DirectoryFilters"; phase="phase:core"; priority="priority:P2"; parallel=$false; story="US6"; body="Add relationship filter dropdown to DirectoryFilters component`nFile: apps/web/src/components/directory/DirectoryFilters.tsx`n- Friends/Following/Followers/Blocked options`n- Combine with other active filters via AND logic`n`n**FR**: FR-007, FR-011" }
