    @{ id="T048"; title="Implement computeProfileCompleteness()"; phase="phase:core"; priority="priority:P3"; parallel=$false; story="US7"; body="Implement computeProfileCompleteness() in apps/web/src/lib/directory/completeness.ts`n- Pure function accepting {avatarUrl, displayName, bio, homeCityId, socialLinkCount}`n- Returns {percentage, fields}`n`n**FR**: FR-026, FR-027`n**Research**: R-5" }
    @{ id="T049"; title="Create ProfileCompleteness component"; phase="phase:core"; priority="priority:P3"; parallel=$false; story="US7"; body="Create ProfileCompleteness component in apps/web/src/components/directory/ProfileCompleteness.tsx`n- Progress bar/ring showing percentage`n- Field-by-field breakdown with check/missing indicators`n- i18n-ready labels`n`n**FR**: FR-026" }
    @{ id="T050"; title="Add ProfileCompleteness to settings page"; phase="phase:core"; priority="priority:P3"; parallel=$false; story="US7"; body="Add ProfileCompleteness to own profile settings page`nFile: apps/web/src/app/settings/profile/page.tsx`n- Render above directory visibility toggle`n- Pass current profile data`n- Show only for own profile`n`n**FR**: FR-026, FR-028" }

