    @{ id="T051"; title="Test: proximity sort tiers + fallback"; phase="phase:core"; priority="priority:P3"; parallel=$true; story="US8"; body="Integration test: proximity sort tiers + sub-sort + no-city fallback`nFile: apps/web/tests/integration/directory/directory-proximity.test.ts`n- Seed users in Bristol/London/Paris/Tokyo`n- Verify tier ordering 1->2->3->4 and alphabetical sub-sort within tiers`n- Test viewer with no home city falls back to pure alphabetical`n`n**FR**: FR-029, FR-030" }
