    @{ id="T055"; title="Extract all directory UI strings for i18n"; phase="phase:polish"; priority="priority:P2"; parallel=$true; story=""; body="Extract all directory UI strings to i18n namespace in apps/web/src/`n- Filter labels, sort options, empty states ('No members found matching your search')`n- Relationship statuses, 'Show me in the community directory'`n- 'People near me', profile completeness field labels`n`n**FR**: FR-035" }
    @{ id="T056"; title="Accessibility audit for directory page"; phase="phase:polish"; priority="priority:P2"; parallel=$true; story=""; body="Accessibility audit for directory page`n- Keyboard navigation for all filter controls`n- Focus management on load-more`n- ARIA labels on filter dropdowns and toggle`n- Screen reader text for DirectoryCard content`n- Skip-to-content link" }
    @{ id="T057"; title="Add aria-labels to SocialIcons component"; phase="phase:polish"; priority="priority:P2"; parallel=$true; story=""; body="Add aria-labels and sr-only text to SocialIcons component`n- Each icon must have accessible name identifying platform`n- E.g. 'Instagram profile', 'LinkedIn profile'" }
    @{ id="T058"; title="Test: muted users still appear in directory"; phase="phase:polish"; priority="priority:P2"; parallel=$true; story=""; body="Verify muted users still appear in directory results`n- Add regression test confirming mute does NOT affect directory presence`nFile: apps/web/tests/integration/directory/directory-relationships.test.ts`n`n**FR**: FR-017" }
    @{ id="T059"; title="Run quickstart.md end-to-end smoke test"; phase="phase:polish"; priority="priority:P2"; parallel=$false; story=""; body="Run quickstart.md end-to-end smoke test`n- Verify all curl examples work`n- Test commands pass`n- Seed data scenarios produce expected results`n- Migration applies and rolls back cleanly" }
)

$created = 0
$failed = 0

foreach ($issue in $issues) {
    $title = "[009] $($issue.id) - $($issue.title)"
    $labels = @("spec:009-directory", $issue.priority, $issue.phase)
    if ($issue.parallel) { $labels += "parallelizable" }
    
    $storyLabel = ""
    if ($issue.story) { $storyLabel = "`n`n**User Story**: $($issue.story)" }
    
    $body = "$($issue.body)$storyLabel`n`n---`n_Auto-generated from specs/009-user-directory/tasks.md_"
    $labelStr = ($labels -join ",")
    
    try {
        $result = & gh issue create --repo $repo --title $title --body $body --label $labelStr 2>&1
        if ($LASTEXITCODE -eq 0) {
            $created++
            Write-Host "OK  $($issue.id): $result" -ForegroundColor Green
        } else {
            $failed++
            Write-Host "ERR $($issue.id): $result" -ForegroundColor Red
        }
    } catch {
        $failed++
        Write-Host "ERR $($issue.id): $_" -ForegroundColor Red
    }
    
    # Small delay to avoid rate limiting
    Start-Sleep -Milliseconds 500
}

Write-Host "`nDone: $created created, $failed failed" -ForegroundColor Cyan
